import React, { useState } from 'react';

const App = () => {
  const [price, setPrice] = useState(19.99);
  const togglePrice = () => {
    setPrice(price === 19.99 ? 14.99 : 19.99);
  };
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] p-4 rounded-lg shadow-md w-80">
        <h2 className="text-lg font-bold mb-2">Price Toggle</h2>
        <p className="text-3xl font-bold mb-4">${price.toFixed(2)}</p>
        <button
className="bg-[#411C56] hover:bg-[#000000] text-white font-bold py-2 px-4 rounded" onClick={togglePrice}>
          Toggle Price
        </button>
      </div>
    </div>
  );
};

export default App;
